CREATE TABLE IF NOT EXISTS tohumlamalar (
    id             BIGSERIAL PRIMARY KEY,
    hayvan_id      INTEGER       NOT NULL,
    sperma         TEXT,
    belge_no       TEXT,
    kupe_no        TEXT,
    irk            TEXT,
    not_           TEXT,
    tohumlama_tar  DATE,
    gebe           BOOLEAN,
    scrape_tarihi  DATE          NOT NULL,
    kaynak_url     TEXT
);

